// Cloudflare Worker for SendGrid Email and Stripe Payment Integration

const ALLOWED_ORIGINS = ['https://yourdomain.com', 'https://www.yourdomain.com'];

const corsHeaders = {
  'Access-Control-Allow-Origin': '*',
  'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
  'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  'Access-Control-Max-Age': '86400',
};

class APIError extends Error {
  constructor(message, statusCode = 500, details = null) {
    super(message);
    this.statusCode = statusCode;
    this.details = details;
  }
}

async function sendEmail(emailData, sendGridApiKey) {
  const { to, from, subject, text, html } = emailData;

  if (!to || !from || !subject || (!text && !html)) {
    throw new APIError('Missing required email fields', 400);
  }

  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRegex.test(to) || !emailRegex.test(from)) {
    throw new APIError('Invalid email format', 400);
  }

  const payload = {
    personalizations: [
      {
        to: [{ email: to }],
      },
    ],
    from: { email: from },
    subject: subject,
    content: [
      {
        type: html ? 'text/html' : 'text/plain',
        value: html || text,
      },
    ],
  };

  try {
    const response = await fetch('https://api.sendgrid.com/v3/mail/send', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${sendGridApiKey}`,
      },
      body: JSON.stringify(payload),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new APIError(
        `SendGrid API error: ${response.statusText}`,
        response.status,
        errorData
      );
    }

    return {
      success: true,
      message: 'Email sent successfully',
      messageId: response.headers.get('X-Message-Id'),
    };
  } catch (error) {
    if (error instanceof APIError) {
      throw error;
    }
    throw new APIError('Failed to send email', 500, error.message);
  }
}

async function createPaymentIntent(paymentData, stripeSecretKey) {
  const { amount, currency = 'usd', description, metadata = {} } = paymentData;

  if (!amount || amount <= 0) {
    throw new APIError('Invalid payment amount', 400);
  }

  if (typeof amount !== 'number' || !Number.isInteger(amount)) {
    throw new APIError('Amount must be an integer in cents', 400);
  }

  const payload = new URLSearchParams({
    amount: amount.toString(),
    currency: currency.toLowerCase(),
  });

  if (description) {
    payload.append('description', description);
  }

  Object.keys(metadata).forEach((key) => {
    payload.append(`metadata[${key}]`, metadata[key]);
  });

  try {
    const response = await fetch('https://api.stripe.com/v1/payment_intents', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': `Bearer ${stripeSecretKey}`,
      },
      body: payload.toString(),
    });

    const data = await response.json();

    if (!response.ok) {
      throw new APIError(
        `Stripe API error: ${data.error?.message || response.statusText}`,
        response.status,
        data.error
      );
    }

    return {
      success: true,
      paymentIntentId: data.id,
      clientSecret: data.client_secret,
      amount: data.amount,
      currency: data.currency,
      status: data.status,
    };
  } catch (error) {
    if (error instanceof APIError) {
      throw error;
    }
    throw new APIError('Failed to create payment intent', 500, error.message);
  }
}

async function retrievePaymentIntent(paymentIntentId, stripeSecretKey) {
  if (!paymentIntentId) {
    throw new APIError('Payment Intent ID is required', 400);
  }

  try {
    const response = await fetch(
      `https://api.stripe.com/v1/payment_intents/${paymentIntentId}`,
      {
        method: 'GET',
        headers: {
          'Authorization': `Bearer ${stripeSecretKey}`,
        },
      }
    );

    const data = await response.json();

    if (!response.ok) {
      throw new APIError(
        `Stripe API error: ${data.error?.message || response.statusText}`,
        response.status,
        data.error
      );
    }

    return {
      success: true,
      paymentIntent: {
        id: data.id,
        amount: data.amount,
        currency: data.currency,
        status: data.status,
        created: data.created,
        description: data.description,
        metadata: data.metadata,
      },
    };
  } catch (error) {
    if (error instanceof APIError) {
      throw error;
    }
    throw new APIError('Failed to retrieve payment intent', 500, error.message);
  }
}

async function handleStripeWebhook(request, stripeWebhookSecret) {
  const signature = request.headers.get('stripe-signature');
  
  if (!signature) {
    throw new APIError('Missing Stripe signature', 400);
  }

  const payload = await request.text();
  
  try {
    const event = JSON.parse(payload);
    
    switch (event.type) {
      case 'payment_intent.succeeded':
        return {
          success: true,
          message: 'Payment succeeded',
          data: {
            paymentIntentId: event.data.object.id,
            amount: event.data.object.amount,
          },
        };
      
      case 'payment_intent.payment_failed':
        return {
          success: true,
          message: 'Payment failed',
          data: {
            paymentIntentId: event.data.object.id,
            error: event.data.object.last_payment_error,
          },
        };
      
      default:
        return {
          success: true,
          message: 'Webhook received',
          eventType: event.type,
        };
    }
  } catch (error) {
    throw new APIError('Invalid webhook payload', 400, error.message);
  }
}

function validateApiKey(request, expectedKey) {
  const authHeader = request.headers.get('Authorization');
  
  if (!authHeader) {
    throw new APIError('Missing Authorization header', 401);
  }

  const [type, token] = authHeader.split(' ');
  
  if (type !== 'Bearer') {
    throw new APIError('Invalid Authorization type', 401);
  }

  if (token !== expectedKey) {
    throw new APIError('Invalid API key', 403);
  }

  return true;
}

function jsonResponse(data, status = 200) {
  return new Response(JSON.stringify(data), {
    status,
    headers: {
      'Content-Type': 'application/json',
      ...corsHeaders,
    },
  });
}

function errorResponse(error) {
  const status = error instanceof APIError ? error.statusCode : 500;
  const message = error.message || 'Internal Server Error';
  const details = error instanceof APIError ? error.details : null;

  return jsonResponse(
    {
      success: false,
      error: message,
      ...(details && { details }),
    },
    status
  );
}

async function handleRequest(request, env) {
  const url = new URL(request.url);
  const path = url.pathname;

  if (request.method === 'OPTIONS') {
    return new Response(null, {
      headers: corsHeaders,
    });
  }

  try {
    validateApiKey(request, env.WORKER_API_KEY);

    if (path === '/api/email/send' && request.method === 'POST') {
      const emailData = await request.json();
      const result = await sendEmail(emailData, env.SENDGRID_API_KEY);
      return jsonResponse(result);
    }

    if (path === '/api/payment/create' && request.method === 'POST') {
      const paymentData = await request.json();
      const result = await createPaymentIntent(paymentData, env.STRIPE_SECRET_KEY);
      return jsonResponse(result);
    }

    if (path.startsWith('/api/payment/') && request.method === 'GET') {
      const paymentIntentId = path.split('/').pop();
      const result = await retrievePaymentIntent(paymentIntentId, env.STRIPE_SECRET_KEY);
      return jsonResponse(result);
    }

    if (path === '/api/webhook/stripe' && request.method === 'POST') {
      const result = await handleStripeWebhook(request, env.STRIPE_WEBHOOK_SECRET);
      return jsonResponse(result);
    }

    if (path === '/health' && request.method === 'GET') {
      return jsonResponse({
        success: true,
        status: 'healthy',
        timestamp: new Date().toISOString(),
      });
    }

    throw new APIError('Endpoint not found', 404);
  } catch (error) {
    console.error('Error handling request:', error);
    return errorResponse(error);
  }
}

addEventListener('fetch', (event) => {
  event.respondWith(handleRequest(event.request, event));
});

export default {
  async fetch(request, env, ctx) {
    return handleRequest(request, env);
  },
};